import{bQ as d,aL as a,u as e,G as r}from"./chunks/framework.D06dwy5q.js";const s=JSON.parse('{"title":"数据库出现","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/06-数据库出现.md","filePath":"00.互联网与架构基础/06-数据库出现.md","lastUpdated":null}'),h={name:"00.互联网与架构基础/06-数据库出现.md"};function o(l,t,p,i,n,b){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="数据库出现" tabindex="-1">数据库出现 <a class="header-anchor" href="#数据库出现" aria-label="Permalink to &quot;数据库出现&quot;">​</a></h1><p>程序总要保存数据。很小的程序可以把数据写进文件，比如一份文本、一个 JSON、几个 CSV。数据少的时候这样很直接，打开文件就能看见。</p><p>数据变多以后，文件会开始吃力。多人同时写会互相覆盖，想按条件查数据要扫整个文件，误删以后恢复麻烦，数据格式也容易写乱。数据库就是为了解决这些保存、查询、并发和恢复问题出现的。</p><h2 id="一、从文件到表" tabindex="-1">一、从文件到表 <a class="header-anchor" href="#一、从文件到表" aria-label="Permalink to &quot;一、从文件到表&quot;">​</a></h2><p>文件适合简单配置和少量记录。业务数据变多以后，会遇到这些问题：</p><table tabindex="0"><thead><tr><th>问题</th><th>表现</th></tr></thead><tbody><tr><td>查询慢</td><td>想找某个用户，要扫完整个文件</td></tr><tr><td>并发难</td><td>多个进程同时写文件，可能互相覆盖</td></tr><tr><td>格式脆弱</td><td>一行写坏，整份文件都不好处理</td></tr><tr><td>约束少</td><td>邮箱、金额、状态值很难统一检查</td></tr><tr><td>恢复麻烦</td><td>误删或写坏后只能靠文件备份</td></tr></tbody></table><p>数据库里的表像结构化的文件，但多了字段类型、约束、索引、事务和查询语言。MySQL 和 PostgreSQL 都属于常见关系型数据库。</p><h2 id="二、表和-sql" tabindex="-1">二、表和 SQL <a class="header-anchor" href="#二、表和-sql" aria-label="Permalink to &quot;二、表和 SQL&quot;">​</a></h2><p>关系型数据库把数据放在表里。表里的每一行是一条记录，每一列是一个字段。</p><p>一个用户表可以这样理解：</p><table tabindex="0"><thead><tr><th>id</th><th>name</th><th>email</th><th>created_at</th></tr></thead><tbody><tr><td>1</td><td>alice</td><td><a href="mailto:alice@example.com" target="_blank" rel="noreferrer">alice@example.com</a></td><td>2026-06-10</td></tr><tr><td>2</td><td>bob</td><td><a href="mailto:bob@example.com" target="_blank" rel="noreferrer">bob@example.com</a></td><td>2026-06-10</td></tr></tbody></table><p>SQL 是用来查询和修改这些表的语言。比如查用户、插入订单、更新任务状态、删除过期记录。</p><p>关系型数据库适合用户、订单、权限、审计、配置这类结构比较清楚的数据。MongoDB 更适合文档结构，Redis 常用作缓存和轻量状态存储，Elasticsearch 常用于检索和日志查询。</p><h2 id="三、事务" tabindex="-1">三、事务 <a class="header-anchor" href="#三、事务" aria-label="Permalink to &quot;三、事务&quot;">​</a></h2><p>事务解决“一组操作要一起成功或一起失败”的问题。</p><p>转账是最常见的例子：A 账户扣 100，B 账户加 100。扣款成功以后程序崩了，如果没有事务，钱可能少了一半。事务会把这两步包在一起，中间任何一步失败就回滚。</p><p>事务常被概括为 ACID：</p><table tabindex="0"><thead><tr><th>特性</th><th>含义</th></tr></thead><tbody><tr><td>原子性</td><td>一组操作整体成功或整体失败</td></tr><tr><td>一致性</td><td>操作前后数据满足约束</td></tr><tr><td>隔离性</td><td>并发事务之间互相影响受控制</td></tr><tr><td>持久性</td><td>提交后的数据不会因为进程退出而消失</td></tr></tbody></table><p>后端接口里很多动作都需要事务，比如创建任务并写审计日志、扣库存并生成订单、更新配置并记录版本。没有事务时，接口返回成功后，关联数据可能只写了一半。</p><h2 id="四、索引" tabindex="-1">四、索引 <a class="header-anchor" href="#四、索引" aria-label="Permalink to &quot;四、索引&quot;">​</a></h2><p>索引用来加快查询。可以把它看成数据库为某些字段额外建的一份查找目录。没有索引时，数据库可能要一行行扫完整张表；有合适索引时，就能更快找到目标记录。</p><p>索引也有成本。它会占磁盘，写入数据时还要同步维护索引结构。经常查询的字段适合建索引，经常变化但很少查询的字段建太多索引，可能让写入变慢。</p><p>接口变慢时，数据库查询经常是原因之一。比如任务表有 100 万行，接口按 <code>status</code> 和 <code>created_at</code> 查询最近失败任务，如果没有合适索引，数据库可能扫描大量历史记录。用户看到的是接口 5 秒才返回，后端日志里看到的是同一条 SQL 反复慢。</p><h2 id="五、缓存" tabindex="-1">五、缓存 <a class="header-anchor" href="#五、缓存" aria-label="Permalink to &quot;五、缓存&quot;">​</a></h2><p>缓存用来减少重复查询。Redis 是最常见的缓存系统之一。</p><p>适合缓存的数据通常有几个特点：读得多、变化不太频繁、短时间内允许轻微延迟。例如用户权限、配置项、排行榜、热点字典、接口统计结果。</p><p>缓存也会带来新问题：</p><table tabindex="0"><thead><tr><th>问题</th><th>表现</th></tr></thead><tbody><tr><td>缓存穿透</td><td>大量查询不存在的数据，打到数据库</td></tr><tr><td>缓存击穿</td><td>热点 key 过期，瞬间大量请求打到数据库</td></tr><tr><td>缓存雪崩</td><td>大量 key 同时过期，数据库压力突然上涨</td></tr><tr><td>数据不一致</td><td>数据库更新了，缓存里还是旧值</td></tr></tbody></table><p>缓存是数据库前面的一层加速。关键数据仍然要能从数据库恢复出来。</p><h2 id="六、复制和备份" tabindex="-1">六、复制和备份 <a class="header-anchor" href="#六、复制和备份" aria-label="Permalink to &quot;六、复制和备份&quot;">​</a></h2><p>数据库承载业务数据以后，要考虑故障和误操作。</p><table tabindex="0"><thead><tr><th>机制</th><th>解决什么</th></tr></thead><tbody><tr><td>主从复制</td><td>主库故障时有从库可接管，读请求也可以分摊</td></tr><tr><td>备份</td><td>数据误删、表损坏、机房故障后能恢复</td></tr><tr><td>binlog / WAL</td><td>记录变更过程，支持增量恢复和复制</td></tr></tbody></table><p>复制和备份不能互相替代。主库误删一张表，从库很可能也会同步删除。备份恢复需要时间，恢复期间业务可能不可用。</p><p>数据库是后端系统保存状态的地方。接口能不能快、发布能不能回滚、故障能不能恢复，很多时候都要回到表结构、索引、事务、复制和备份上。</p>',34)])])}const _=d(h,[["render",o]]);export{s as __pageData,_ as default};
